  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function rand(min, max) {
    return Math.random() * (max - min) + min;
  }

  function randi(min, max) {
    return Math.floor(rand(min, max + 1));
  }

  function pick(list) {
    return list[Math.floor(Math.random() * list.length)];
  }

  function chance(value) {
    return Math.random() < value;
  }

  function dist(a, b) {
    return Math.hypot(a.x - b.x, a.y - b.y);
  }

  function angleTo(a, b) {
    return Math.atan2(b.y - a.y, b.x - a.x);
  }

  function angleDelta(a, b) {
    let d = (a - b + Math.PI) % TAU - Math.PI;
    if (d < -Math.PI) d += TAU;
    return d;
  }

  function weighted(list) {
    const total = list.reduce((sum, item) => sum + item.weight, 0);
    let roll = Math.random() * total;
    for (const item of list) {
      roll -= item.weight;
      if (roll <= 0) return item;
    }
    return list[list.length - 1];
  }

  function uid(prefix = "id") {
    return `${prefix}-${Math.random().toString(36).slice(2, 10)}`;
  }

  function title(value) {
    return value.charAt(0).toUpperCase() + value.slice(1);
  }

  function slotLabel(slot) {
    return SLOT_LABELS[slot] || slot;
  }

  function materialLabel(material) {
    if (String(material || "").endsWith("Gem")) {
      const powerId = String(material).slice(0, -"Gem".length);
      const power = POWERS.find((entry) => entry.id === powerId);
      if (power) return `Ngọc ${power.name}`;
    }
    return MATERIAL_LABELS[material] || title(material);
  }

  function awakeningGemMaterial(powerId) {
    return `${powerId}Gem`;
  }

  function awakeningRaidBiomeId(powerId) {
    return AWAKENING_RAID_BIOMES[powerId] || "forest";
  }

  function upgradeLabel(stat) {
    return UPGRADE_LABELS[stat] || title(stat);
  }

  function customLabel(value) {
    return CUSTOM_LABELS[value] || title(value);
  }

  function characterById(id) {
    return CHARACTER_TYPES.find((character) => character.id === id) || CHARACTER_TYPES[0];
  }

  function powerById(id) {
    return POWERS.find((power) => power.id === id) || POWERS[0];
  }

  function itemById(id) {
    return ITEMS.find((item) => item.id === id) || null;
  }

  function bossDebuffById(id) {
    return BOSS_DEBUFFS.find((effect) => effect.id === id) || null;
  }

  function secretRiddleById(id) {
    return SECRET_RIDDLES.find((riddle) => riddle.id === id) || SECRET_RIDDLES[0];
  }

  function secretPuzzleGlyphs(riddle) {
    const glyphs = {
      emberGlass: ["HỎA", "TÀN", "LÒ", "NHIỆT"],
      frostCore: ["BĂNG", "GƯƠNG", "TUYẾT", "LẠNH"],
      stormThread: ["SÉT", "MÂY", "CHỚP", "BÃO"],
      bloodAmber: ["MÁU", "TIM", "MẠCH", "HỒI"],
      bossCore: ["TRÙM", "LÕI", "ẤN", "VƯƠNG"]
    };
    return glyphs[riddle?.material] || ["ẤN", "MẢNH", "KHÓA", "MỞ"];
  }

  function accountKey(username) {
    return (username || "").trim().toLowerCase();
  }

  function escapeHtml(value = "") {
    return String(value).replace(/[&<>"']/g, (char) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      "\"": "&quot;",
      "'": "&#39;"
    }[char]));
  }

  function hashText(value) {
    let hash = 2166136261;
    for (let i = 0; i < value.length; i++) {
      hash ^= value.charCodeAt(i);
      hash = Math.imul(hash, 16777619);
    }
    return (hash >>> 0).toString(16).padStart(8, "0");
  }

  function passwordHash(username, password) {
    return hashText(`${accountKey(username)}:${password}`);
  }

  function cloneData(value) {
    return typeof structuredClone === "function" ? structuredClone(value) : JSON.parse(JSON.stringify(value));
  }

  function withTimeout(promise, timeoutMs, fallback = null) {
    return Promise.race([
      Promise.resolve(promise).catch(() => fallback),
      new Promise((resolve) => setTimeout(() => resolve(fallback), timeoutMs))
    ]);
  }

  async function fetchWithTimeout(url, options = {}, timeoutMs = CLOUD_REQUEST_TIMEOUT_MS) {
    const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
    const fetchOptions = { ...options };
    const externalSignal = fetchOptions.signal;
    let abortExternal = null;
    if (controller) {
      fetchOptions.signal = controller.signal;
      if (externalSignal) {
        if (externalSignal.aborted) controller.abort();
        else {
          abortExternal = () => controller.abort();
          externalSignal.addEventListener("abort", abortExternal, { once: true });
        }
      }
    }
    const timer = controller ? setTimeout(() => controller.abort(), timeoutMs) : 0;
    const response = await withTimeout(fetch(url, fetchOptions), timeoutMs + 120, null);
    if (timer) clearTimeout(timer);
    if (externalSignal && abortExternal) externalSignal.removeEventListener("abort", abortExternal);
    if (!response) throw new Error("Request timed out");
    return response;
  }

