          this.bossLineDanger(enemy, enemy.x - Math.cos(aim + offset) * 180, enemy.y - Math.sin(aim + offset) * 180, aim + offset, 620 + phase * 70, 24 + phase * 4, 0.72 + Math.abs(offset) * 0.35, 0.5, color);
